{
  "command": "duckdb '/Users/shreyashankar/Documents/projects/DataAgentBench/query_music_brainz_20k/query_dataset/sales.duckdb' \"SELECT track_id, SUM(revenue_usd) AS total_rev FROM sales GROUP BY track_id ORDER BY total_rev DESC LIMIT 5\"",
  "description": "Find top revenue track_ids"
}

{
  "command": "sqlite3 '/Users/shreyashankar/Documents/projects/DataAgentBench/query_music_brainz_20k/query_dataset/tracks.db' \"SELECT track_id, title, artist, album FROM tracks WHERE track_id IN (14719, 5124, 1344, 6725, 10377)\"",
  "description": "Look up track titles for top ids"
}

{
  "command": "duckdb '/Users/shreyashankar/Documents/projects/DataAgentBench/query_music_brainz_20k/query_dataset/sales.duckdb' \"ATTACH '/Users/shreyashankar/Documents/projects/DataAgentBench/query_music_brainz_20k/query_dataset/tracks.db' AS t (TYPE SQLITE); SELECT tr.title, tr.artist, SUM(s.revenue_usd) AS total_rev FROM sales s JOIN t.tracks tr ON s.track_id = tr.track_id GROUP BY tr.title, tr.artist ORDER BY total_rev DESC LIMIT 10;\"",
  "description": "Aggregate revenue by title+artist"
}

{
  "command": "duckdb '/Users/shreyashankar/Documents/projects/DataAgentBench/query_music_brainz_20k/query_dataset/sales.duckdb' \"ATTACH '/Users/shreyashankar/Documents/projects/DataAgentBench/query_music_brainz_20k/query_dataset/tracks.db' AS t (TYPE SQLITE); SELECT tr.title, tr.artist, SUM(s.revenue_usd) AS total_rev FROM sales s JOIN t.tracks tr ON s.track_id = tr.track_id WHERE tr.title IS NOT NULL AND tr.artist IS NOT NULL GROUP BY tr.title, tr.artist ORDER BY total_rev DESC LIMIT 5;\"",
  "description": "Aggregate revenue by title+artist excluding nulls"
}
